   261→	@LogExecution()
   262→	async waitForTask({
   263→		taskId,
   264→		intervalMs = 5000,
   265→		maxAttempts = 60,
   266→	}: {
   267→		taskId: string;
   268→		intervalMs?: number;
   269→		maxAttempts?: number;
   270→	}): Promise<{ state: string; model_id?: string }> {
   271→		for (let attempt = 1; attempt <= maxAttempts; attempt++) {
   272→			const task = await this.getTask({ taskId });
   273→			this.logger.log(
   274→				`Task ${taskId} — attempt ${attempt}/${maxAttempts}, state: ${task.state}`,
   275→			);
   276→
   277→			if (task.state === 'COMPLETED') {
   278→				return task;
   279→			}
   280→
   281→			if (task.state === 'FAILED') {
   282→				throw new Error(`Task ${taskId} failed`);
   283→			}
   284→
   285→			await new Promise((resolve) => setTimeout(resolve, intervalMs));
   286→		}
   287→
   288→		throw new Error(`Task ${taskId} timed out after ${maxAttempts} attempts`);
