    53→		const batchSize = options.batchSize ?? 150;
    54→		const concurrency = options.concurrency ?? 5;
    55→		const createIndex = options.createIndex ?? false;
    56→		const recreateIndex = options.recreateIndex ?? false;
    57→
    58→		try {
    59→			const indexName = this.configService.get<string>({ key: OPENSEARCH_INDEX_NAME });
    60→
    61→			if (recreateIndex) {
    62→				this.logger.log(`Dropping OpenSearch index: ${indexName}`);
    63→				await this.opensearchService.deleteIndex({ indexName });
    64→				this.logger.log(`Creating OpenSearch index: ${indexName}`);
    65→				await this.opensearchNeuralService.createProductsIndex({ indexName });
    66→			} else if (createIndex) {
    67→				this.logger.log(`Creating OpenSearch index: ${indexName}`);
    68→				await this.opensearchNeuralService.createProductsIndex({ indexName });
    69→			}
    70→
    71→			this.logger.log('Starting to reindex products to OpenSearch');
    72→			this.logger.log(`Batch size: ${batchSize}, Concurrency: ${concurrency}`);
    73→
    74→			const totalCount = await this.stylesMvModel.count();
    75→			this.logger.log(`Total products to index: ${totalCount}`);
    76→
    77→			if (totalCount === 0) {
    78→				this.logger.warn('No products found to index');
    79→				return;
    80→			}
    81→
    82→			const totalBatches = Math.ceil(totalCount / batchSize);
    83→			const batches = Array.from({ length: totalBatches }, (_, i) => ({
    84→				offset: i * batchSize,
    85→				limit: batchSize,
    86→			}));
