   127→	private async processBatches({
   128→		batches,
   129→		concurrency,
   130→		indexName,
   131→		progressBar,
   132→		onBatchComplete,
   133→	}: {
   134→		batches: { offset: number; limit: number }[];
   135→		concurrency: number;
   136→		indexName: string;
   137→		progressBar: ProgressBar;
   138→		onBatchComplete: (indexed: number, errors: number) => void;
   139→	}): Promise<void> {
   140→		await runWithConcurrencyLimit({
   141→			items: batches,
   142→			concurrency,
   143→			handler: async (batch) => {
   144→				if (this.isCancelled) {
   145→					return { indexed: 0, errors: 0 };
   146→				}
   147→
   148→				const styles = await this.stylesMvModel.findAll({
   149→					limit: batch.limit,
   150→					offset: batch.offset,
   151→				});
   152→
   153→				if (styles.length === 0) {
   154→					return { indexed: 0, errors: 0 };
   155→				}
   156→
   157→				const result = await this.opensearchNeuralService.bulkIndexProducts({
   158→					indexName,
   159→					styles,
   160→				});
   161→
   162→				return result;
   163→			},
   164→			onItemComplete: (result) => {
   165→				progressBar.increment(result.indexed + result.errors);
   166→				onBatchComplete(result.indexed, result.errors);
   167→			},
   168→			onItemError: (error) => {
   169→				this.logger.error(`Batch processing error: ${(error as Error).message}`);
   170→			},
   171→		});
   172→	}
