   215→	private setupGracefulShutdown(): void {
   216→		const signals: NodeJS.Signals[] = ['SIGTERM', 'SIGINT', 'SIGHUP', 'SIGQUIT'];
   217→
   218→		signals.forEach((signal) => {
   219→			process.on(signal, () => {
   220→				void this.handleShutdown(signal);
   221→			});
   222→		});
   223→
   224→		process.on('uncaughtException', (error) => {
   225→			this.logger.error(`Uncaught exception: ${error.message}`);
   226→			void this.handleShutdown('SIGTERM');
   227→		});
   228→
   229→		process.on('unhandledRejection', (reason) => {
   230→			this.logger.error(`Unhandled rejection: ${String(reason)}`);
   231→			void this.handleShutdown('SIGTERM');
   232→		});
   233→	}
   234→
   235→	private async handleShutdown(signal: string): Promise<void> {
   236→		if (this.isShuttingDown) {
   237→			this.logger.warn('Force shutdown requested, exiting immediately');
   238→			process.exit(1);
   239→		}
   240→
   241→		this.logger.warn(`Received ${signal} signal, initiating graceful shutdown...`);
   242→		this.isShuttingDown = true;
   243→		this.isCancelled = true;
   244→
   245→		try {
   246→			if (this.currentOperation) {
   247→				this.logger.log('Waiting for current operation to complete...');
   248→
   249→				const shutdownTimeout = setTimeout(() => {
   250→					this.logger.error('Graceful shutdown timeout, forcing exit');
   251→					process.exit(1);
   252→				}, 30000);
   253→
   254→				await this.currentOperation;
   255→				clearTimeout(shutdownTimeout);
   256→			}
   257→
   258→			this.logger.log('Graceful shutdown completed');
   259→			process.exit(0);
   260→		} catch (error) {
   261→			this.logger.error(`Error during shutdown: ${(error as Error).message}`);
   262→			process.exit(1);
   263→		}
   264→	}
   265→}
